query:
SELECT 
  COUNT(*) as total_leads,
  SUM(CASE WHEN status = 'new' THEN 1 ELSE 0 END) as new_leads,
  SUM(CASE WHEN status = 'contacted' THEN 1 ELSE 0 END) as contacted,
  SUM(CASE WHEN status = 'qualified' THEN 1 ELSE 0 END) as qualified,
  SUM(CASE WHEN status = 'closed_won' THEN 1 ELSE 0 END) as won,
  SUM(CASE WHEN status = 'closed_lost' THEN 1 ELSE 0 END) as lost,
  SUM(CASE WHEN ghlWebhookSent = 1 THEN 1 ELSE 0 END) as ghl_webhook_sent,
  SUM(CASE WHEN ghlWebhookSent = 0 THEN 1 ELSE 0 END) as ghl_webhook_not_sent,
  SUM(CASE WHEN createdAt >= DATE_SUB(NOW(), INTERVAL 24 HOUR) THEN 1 ELSE 0 END) as last_24h,
  SUM(CASE WHEN createdAt >= DATE_SUB(NOW(), INTERVAL 7 DAY) THEN 1 ELSE 0 END) as last_7_days
FROM leads;

SELECT sourcePage, COUNT(*) as count FROM leads GROUP BY sourcePage ORDER BY count DESC;

SELECT formName, COUNT(*) as count FROM leads GROUP BY formName ORDER BY count DESC;

SELECT DATE(createdAt) as date, COUNT(*) as leads_per_day FROM leads GROUP BY DATE(createdAt) ORDER BY date DESC LIMIT 14;

SELECT * FROM leads ORDER BY createdAt DESC LIMIT 10;
